  (449, 'ecute', '执行', 'follow, pursue', NULL),
  (450, 'edi', '听', 'hear', '拉丁语动词audire（听）及其完成分词auditus。著名德国汽车品牌奥迪（Audi）的含义就是“听”。它的创始人是德国人奥古斯特·霍希（AugustHorch）。霍希这个姓氏在德语中就是“听”的意思，被他所创办的第一家汽车公司用作了品牌，所以他创办第二家汽车公司时，不能再使用自己的姓氏，就改用拉丁语中表示“听”的单词audi来作为品牌。常见变体形式：ey/edi'),
  (451, 'educate', '教育', 'lead out, educate', NULL),
  (452, 'effect', '做;制造;使得', 'do, make', '拉丁语动词facere（=make，做，制作，使得）及其完成分词factus常见变体形式：fic/fect，feat/fair/fit'),
  (453, 'effici', '效率;做', 'do, make', NULL),
